import { Action, Ctx, On, Update } from 'nestjs-telegraf';
import { TireStateService } from './tireStateService';
import { RedisService } from '../redis/redis.service';
import { Markup } from 'telegraf';

@Update()
export class BotHandler {
  constructor(
    private readonly stateService: TireStateService,
    private readonly redis: RedisService,
  ) {}

  @On('text')
  async handleText(@Ctx() ctx: any) {
    const tgId = BigInt(ctx.from.id);
    const text = ctx.message.text;

    // Start logic
    if (text === "➕ Yangi shina qo'shish") {
      await this.redis.setUserState(tgId, {
        step: 'WAIT_NAME',
        data: { photos: [] },
      });
      return ctx.reply('Ismini kiriting:');
    }

    // Step logic
    const result = await this.stateService.nextStep(tgId, text);
    if (result?.error) return ctx.reply(result.error);
    if (result?.message) return ctx.reply(result.message);
  }

  @On('photo')
  async handlePhoto(@Ctx() ctx: any) {
    const tgId = BigInt(ctx.from.id);
    const fileId = ctx.message.photo.pop().file_id;

    const state = await this.redis.getUserState(tgId);
    if (state?.step === 'WAIT_PHOTOS') {
      state.data.photos.push(fileId);
      await this.redis.setUserState(tgId, state);
      return ctx.reply(
        'Yana rasm bormi?',
        Markup.inlineKeyboard([
          Markup.button.callback('✅ Saqlash', 'finalize'),
        ]),
      );
    }
  }

  @Action('finalize')
  async handleFinalize(@Ctx() ctx: any) {
    // ... tiresService.createTireFromBot ni chaqirish
  }
}

