@Update()
@Injectable()
export class BotService {
  constructor(
    private readonly prisma: PrismaService,
    @InjectBot() private bot: Telegraf<Context>,
    private readonly configService: ConfigService,
    private readonly mediaservice: MediaService,
    private readonly redis: RedisService,
  ) {}

  @Start()
  async onStart(@Ctx() ctx: Context) {
    if (!ctx.from) return;

    const isAdmin = await this.getAdminByTgId(BigInt(ctx.from.id));

    if (isAdmin) {
      return await ctx.reply(
        'Xush kelibsiz, Admin! 🛠',
        Markup.keyboard([["➕ Yangi shina qo'shish"]]).resize(),
      );
    }

    return await ctx.reply(
      "Xush kelibsiz! Shina qidirish uchun shina nomini yoki o'lchamini yozib yuboring.",
      Markup.removeKeyboard(), // Oddiy foydalanuvchida tugmalar bo'lmaydi
    );
  }

  @On('text')
  async onText(@Ctx() ctx: Context) {
    if (
      !ctx.from ||
      !('message' in ctx.update) ||
      !('text' in ctx.update.message)
    ) {
      return;
    }
    const tgId = BigInt(ctx.from.id);
    const text = ctx.update.message.text;
    const state = await this.redis.getUserState(tgId);

    // 1. Admin shina qo'shishni boshlashi
    if (text === "➕ Yangi shina qo'shish") {
      const isAdmin = await this.getAdminByTgId(tgId);
      if (isAdmin) {
        await this.redis.setUserState(tgId, {
          step: 'WAIT_NAME',
          data: { photos: [] },
        });
        return ctx.reply(
          'Yangi shina nomini kiriting:',
          Markup.keyboard([['❌ Bekor qilish']]).resize(),
        );
      }
    }

    // 2. Bekor qilish logikasi
    if (text === '❌ Bekor qilish' && state) {
      await this.redis.deleteUserState(tgId);
      const isAdmin = await this.getAdminByTgId(tgId);
      return ctx.reply(
        'Jarayon bekor qilindi.',
        isAdmin
          ? Markup.keyboard([["➕ Yangi shina qo'shish"]]).resize()
          : Markup.removeKeyboard(),
      );
    }

    // 3. Shina qo'shish steplari
    if (state && state.step.startsWith('WAIT_')) {
      switch (state.step) {
        case 'WAIT_NAME':
          state.data.name = text;
          state.step = 'WAIT_SIZE';
          await this.redis.setUserState(tgId, state);
          return ctx.reply("O'lchamini kiriting (Masalan: 205/55 R16):");

        case 'WAIT_SIZE':
          state.data.size = text;
          state.step = 'WAIT_PRICE';
          await this.redis.setUserState(tgId, state);
          return ctx.reply('Narxini kiriting (faqat raqam):');

        case 'WAIT_PRICE':
          if (isNaN(Number(text)))
            return ctx.reply('Iltimos, narxni faqat raqamda kiriting!');
          state.data.price = Number(text);
          state.step = 'WAIT_COUNT';
          await this.redis.setUserState(tgId, state);
          return ctx.reply('Soni (dona):');

        case 'WAIT_COUNT':
          if (isNaN(Number(text)))
            return ctx.reply('Iltimos, sonini faqat raqamda kiriting!');
          state.data.count = Number(text);
          state.step = 'WAIT_PHOTOS';
          await this.redis.setUserState(tgId, state);
          return ctx.reply(
            "Endi rasm(lar)ni yuboring (Max: 2 ta). Tugatgach '✅ Saqlash' ni bosing.",
            Markup.inlineKeyboard([
              Markup.button.callback('✅ Saqlash', 'finalize_tire'),
            ]),
          );
      }
      return;
    }

    // 4. Qidiruv logikasi
    return this.searchTires(ctx, text);
  }

  @On('photo')
  async onPhoto(@Ctx() ctx: Context) {
    const tgId = BigInt(ctx.from?.id || 0);
    const state = await this.redis.getUserState(tgId);

    // 1. Bizga message va uning ichida photo massivi borligi aniq bo'lishi kerak
    if (!('message' in ctx.update) || !('photo' in ctx.update.message)) {
      return;
    }

    if (state && state.step === 'WAIT_PHOTOS') {
      // 2. Endi TypeScript photo borligiga ishonadi
      const photos = ctx.update.message.photo;
      const fileId = photos[photos.length - 1].file_id; // pop() o'rniga oxirgi elementni olish xavfsizroq

      if (state.data.photos.length >= 2) {
        return ctx.reply('Maksimal 2 ta rasm yuklash mumkin!');
      }

      state.data.photos.push(fileId);
      await this.redis.setUserState(tgId, state);

      return ctx.reply(
        `Rasm qabul qilindi (${state.data.photos.length}/2).`,
        Markup.inlineKeyboard([
          Markup.button.callback('✅ Saqlash', 'finalize_tire'),
        ]),
      );
    }
  }

  @Action('finalize_tire')
  async onFinalize(@Ctx() ctx: Context) {
    if (
      !ctx.from ||
      !('message' in ctx.update) ||
      !('text' in ctx.update.message)
    ) {
      return;
    }
    const tgId = BigInt(ctx.from.id);
    const state = await this.redis.getUserState(tgId);

    if (!state || state.data.photos.length === 0) {
      return ctx.answerCbQuery('Kamida bitta rasm yuklashingiz kerak!', {
        show_alert: true,
      });
    }

    await ctx.editMessageText("⏳ Ma'lumotlar saqlanmoqda...");

    try {
      const { step, ...tireData } = state;
      await this.createTireFromBot(state.data, state.data.photos);

      await this.redis.deleteUserState(tgId);
      await ctx.reply("✅ Shina bazaga muvaffaqiyatli qo'shildi!");
      return ctx.answerCbQuery();
    } catch (error) {
      console.error(error);
      await ctx.reply('❌ Xatolik yuz berdi.');
      return ctx.answerCbQuery();
    }
  }

  private async searchTires(ctx: Context, query: string) {
    // Shina qidirish logikasi (bazadan query bo'yicha qidirish)
    await ctx.reply(`🔍 "${query}" bo'yicha shinalar qidirilmoqda...`);
    // const tires = await this.prisma.tire.findMany({ where: { name: { contains: query } } });
  }

  async getAdminByTgId(telegramId: bigint) {
    return this.prisma.admin.findUnique({
      where: { telegram_id: telegramId },
    });
  }

  async createTireFromBot(payload: CreateTireDto, tgFileIds: string[]) {
    const botToken = this.configService.get<string>('BOT_TOKEN');
    if (!botToken) throw new NotFoundException('Bot token not found');

    const uploadedPhotos: { url: string; publicId: string }[] = [];

    for (const id of tgFileIds) {
      const result = await this.mediaservice.uploadTelegramPhotoToCloudinary(
        id,
        botToken,
      );

      uploadedPhotos.push({ url: result.url, publicId: result.publicId });
    }
    return await this.prisma.$transaction(async (tx) => {
      try {
        const newTire = await tx.tire.create({
          data: {
            ...payload,
            photos: {
              create: uploadedPhotos,
            },
          },
        });
        return { success: true, tire_id: newTire.id };
      } catch (error) {
        console.log(error);
        throw new InternalServerErrorException('Serverda hatolik');
      }
    });
  }
}

import { Injectable } from '@nestjs/common';
import { RedisService } from '../redis/redis.service';

@Injectable()
export class TireStateService {
  constructor(private readonly redis: RedisService) {}

  async nextStep(tgId: bigint, text: string) {
    const state = await this.redis.getUserState(tgId);
    if (!state) return null;

    const stepMap = {
      WAIT_NAME: {
        next: 'WAIT_SIZE',
        field: 'name',
        msg: "O'lchamini kiriting:",
      },
      WAIT_SIZE: {
        next: 'WAIT_PRICE',
        field: 'size',
        msg: 'Narxini kiriting:',
      },
      WAIT_PRICE: {
        next: 'WAIT_COUNT',
        field: 'price',
        msg: 'Soni kiriting:',
        isNum: true,
      },
      WAIT_COUNT: {
        next: 'WAIT_PHOTOS',
        field: 'count',
        msg: 'Rasmlarni yuboring:',
        isNum: true,
      },
    };

    const current = stepMap[state.step];
    if (!current) return null;

    // Raqam bo'lishi kerak bo'lgan maydonlarni tekshirish
    const value = current.isNum ? Number(text) : text;
    if (current.isNum && isNaN(value as number))
      return { error: 'Iltimos, raqam kiriting!' };

    state.data[current.field] = value;
    state.step = current.next;

    await this.redis.setUserState(tgId, state);
    return { message: current.msg, state };
  }
}

import {
  Controller,
  Post,
  Delete,
  Get,
  Param,
  Query,
  UploadedFile,
  UseInterceptors,
  ParseFilePipe,
  MaxFileSizeValidator,
  FileTypeValidator,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { CloudinaryService } from './cloudinary.service';

@Controller('cloudinary')
export class CloudinaryController {
  constructor(private readonly cloudinaryService: CloudinaryService) {}

  @Post('upload')
  @UseInterceptors(FileInterceptor('file'))
  async uploadFile(
    @UploadedFile(
      new ParseFilePipe({
        validators: [
          new MaxFileSizeValidator({ maxSize: 100 * 1024 * 1024 }),
          new FileTypeValidator({ fileType: 'image\/.*' }),
        ],
        errorHttpStatusCode: 400,
      }),
    )
    file: Express.Multer.File,
    @Query('folder') folder?: string,
  ) {
    return this.cloudinaryService.uploadFile(file, folder);
  }

  @Delete('delete')
  async deleteFile(
    @Query('publicId') publicId: string,
    @Query('type') type: 'image' | 'raw' = 'image',
  ) {
    await this.cloudinaryService.deleteFile(publicId, type);
    return { message: `Fayl muvaffaqiyatli o'chirildi`, publicId };
  }

  @Get('folder/:name')
  async getFolderResources(@Param('name') name: string) {
    return this.cloudinaryService.getResourcesByFolder(name);
  }
}

import {
  BadRequestException,
  Injectable,
  InternalServerErrorException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { v2 as cloudinary } from 'cloudinary';

@Injectable()
export class CloudinaryService {
  constructor(private configService: ConfigService) {
    cloudinary.config({
      cloud_name: this.configService.get<string>('CLOUDINARY_CLOUD_NAME'),
      api_key: this.configService.get<string>('CLOUDINARY_API_KEY'),
      api_secret: this.configService.get<string>('CLOUDINARY_API_SECRET'),
    });
  }

  async uploadFile(
    file: Express.Multer.File,
    folder: string = 'shina',
  ): Promise<{ url: string; publicId: string; resourceType: string }> {
    return new Promise((resolve, reject) => {
      const upload = cloudinary.uploader.upload_stream(
        {
          folder: folder,
          resource_type: 'auto',
        },
        (error, result) => {
          if (error) {
            // Cloudinary xatolarini tahlil qilish
            if (error.message.includes('File size too large')) {
              return reject(
                new BadRequestException(
                  'Fayl hajmi Cloudinary limiti (max 20-100MB) dan oshib ketdi.',
                ),
              );
            }
            if (error.message.includes('Invalid image file')) {
              return reject(
                new BadRequestException(
                  'Yuborilgan fayl formati yaroqsiz yoki buzilgan.',
                ),
              );
            }
            // Umumiy xato
            return reject(
              new InternalServerErrorException(
                `Cloudinary xatoligi: ${error.message}`,
              ),
            );
          }
          if (result) {
            resolve({
              url: result.secure_url,
              publicId: result.public_id,
              resourceType: result.resource_type,
            });
          } else {
            reject(
              new InternalServerErrorException(
                'Yuklash muvaffaqiyatsiz: Natija qaytmadi',
              ),
            );
          }
        },
      );
      if (!file || !file.buffer) {
        return reject(
          new BadRequestException(
            "Fayl ma'lumotlari topilmadi (buffer empty).",
          ),
        );
      }
      upload.end(file.buffer);
    });
  }

  async deleteFile(publicId: string, resourceType: 'image' | 'raw' = 'image') {
    try {
      const result = await cloudinary.uploader.destroy(publicId, {
        resource_type: resourceType,
      });
      if (result.result !== 'ok' && result.result !== 'not found') {
        throw new Error(result.result);
      }
      return result;
    } catch (error) {
      throw new Error(`Cloudinary delete failed: ${error.message}`);
    }
  }

  async getResourcesByFolder(folderName: string) {
    try {
      const resources = await cloudinary.search
        .expression(`folder="${folderName}"`)
        .max_results(500)
        .execute();

      return resources.resources.map((resource: any) => ({
        url: resource.secure_url,
        publicId: resource.public_id,
        type: resource.resource_type,
        format: resource.format,
        size: resource.bytes,
      }));
    } catch (error) {
      throw new Error(`Failed to get resources: ${error.message}`);
    }
  }

  // CloudinaryService ichiga qo'shish uchun
  async uploadFromBuffer(
    buffer: Buffer,
    folder: string = 'tires',
  ): Promise<string | undefined> {
    return new Promise((resolve, reject) => {
      const uploadStream = cloudinary.uploader.upload_stream(
        { folder },
        (error, result) => {
          if (error) return reject(error);
          resolve(result?.secure_url); // Bizga faqat URL kerak bo'lsa
        },
      );
      uploadStream.end(buffer);
    });
  }
}

