import { Type } from 'class-transformer';
import {
  IsString,
  IsNumber,
  IsArray,
  IsOptional,
  Min,
  IsNotEmpty,
} from 'class-validator';

export class CreateTireDto {
  @IsString()
  @IsNotEmpty()
  name: string; // Masalan: Lassa Multiways

  @IsString()
  @IsNotEmpty()
  size: string; // Masalan: 205/55 R16

  @IsNumber({ maxDecimalPlaces: 2 }) // Verguldan keyin 2 ta raqamgacha ruxsat
  @Min(0)
  @Type(() => Number) // BU JUDA MUHIM: Stringni Numberga o'giradi
  price: number;

  @IsNumber()
  @Min(0)
  @Type(() => Number) // String bo'lib kelgan sonni Numberga o'giradi
  count: number;
}

import {
  Body,
  Controller,
  Post,
  UploadedFiles,
  UseInterceptors,
} from '@nestjs/common';
import { TiresService } from './tires.service';
import { CreateTireDto } from './dto/create-tire.dto';
import { FilesInterceptor } from '@nestjs/platform-express';
import { ApiBody, ApiConsumes } from '@nestjs/swagger';

@Controller('tires')
export class TiresController {
  constructor(private readonly tiresService: TiresService) {}

  @Post('create')
  @ApiConsumes('multipart/form-data')
  @ApiBody({
    schema: {
      type: 'object',
      properties: {
        nomi: { type: 'string', description: 'Nomi' },
        razmer: { type: 'string', description: 'Shina razmerlari' },
        narx: { type: 'number', description: 'Narxi' },
        soni: { type: 'number', description: 'Soni' },
        photos: {
          type: 'array',
          items: { type: 'string', format: 'binary' },
          description: 'Shina suratlari(max 2 ta)',
        },
      },
      required: ['nomi', 'razmer', 'narx', 'soni', 'photos'],
    },
  })
  @UseInterceptors(FilesInterceptor('photos', 2))
  async createTire(
    @Body() body: CreateTireDto,
    @UploadedFiles() files: Express.Multer.File[],
  ) {
    return await this.tiresService.create(body);
  }
}

// tires.service.ts
import {
  Injectable,
  InternalServerErrorException,
  NotFoundException,
} from '@nestjs/common';
import { CloudinaryService } from '../cloudinary/cloudinary.service';
import { CreateTireDto } from './dto/create-tire.dto';
import { PrismaService } from 'src/core/database/prisma.service';
import { Context } from 'telegraf';
import axios from 'axios';

@Injectable()
export class TiresService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly cloudinary: CloudinaryService,
  ) {}

  /**
   * Telegramdan kelgan rasm bufferini Cloudinary-ga yuklash
   */
  async uploadTireImage(fileBuffer: Buffer, fileName: string): Promise<string> {
    // CloudinaryService uploadFile Multer obyektini kutyapti,
    // shuning uchun biz unga kerakli strukturani yasab beramiz
    const fakeFile = {
      buffer: fileBuffer,
    } as Express.Multer.File;

    const uploaded = await this.cloudinary.uploadFile(
      fakeFile,
      'tires_warehouse',
    );
    return uploaded.url; // Cloudinary secure_url qaytaradi
  }

  /**
   * Yangi shina yaratish
   */
  async create(createTireDto: CreateTireDto) {
    return this.prisma.$transaction(async (tx) => {
      try {
        const newTire = await tx.tire.create({
          data: {
            name: createTireDto.name,
            size: createTireDto.size,
            price: Number(createTireDto.price),
            count: Number(createTireDto.count),
          },
          select: { id: true },
        });

        return { success: true, tire_id: newTire.id };
      } catch (e) {
        console.log(e);
      }
    });
  }

  /**
   * Barcha shinalarni qidirish (Filter bilan)
   */
  async findAll(query?: string) {
    return this.prisma.tire.findMany({
      where: query
        ? {
            OR: [
              { name: { contains: query, mode: 'insensitive' } },
              { size: { contains: query, mode: 'insensitive' } },
            ],
          }
        : {},
      orderBy: { createdAt: 'desc' },
    });
  }

  /**
   * ID bo'yicha topish
   */
  async findOne(id: string) {
    const tire = await this.prisma.tire.findUnique({
      where: { id },
      include: { photos: true },
    });
    if (!tire) throw new NotFoundException('Shina topilmadi');
    return tire;
  }

  /**
   * Shinani o'chirish (Cloudinary-dan ham rasmini o'chirish imkoniyati bilan)
   */
  async remove(id: string) {
    return await this.prisma.$transaction(async (tx) => {
      const tire = await tx.tire.findUnique({
        where: { id },
        include: { photos: true },
      });

      if (!tire) {
        throw new NotFoundException('Tovar topilmadi');
      }
      // 1. Cloudinary-dan rasmlarni o'chirish
      if (tire.photos && tire.photos.length > 0) {
        for (const photo of tire.photos) {
          const photoObj = photo as { publicId: string };
          await this.cloudinary.deleteFile(photoObj.publicId);
        }
      }

      // 2. Bazadan o'chirish
      return tx.tire.delete({ where: { id } });
    });
  }

  // tires.service.ts yoki util faylda
  async saveTelegramPhoto(ctx: Context, fileId: string) {
    const link = await ctx.telegram.getFileLink(fileId);
    const response = await axios.get(link.href, {
      responseType: 'arraybuffer',
    });
    const buffer = Buffer.from(response.data);

    // Cloudinary-ga yuklash va tayyor natijani olish
    return this.cloudinary.uploadFromBuffer(buffer, 'tires');
  }
}
